const Q_COMMERCE_2006=[{"id": "objective>Commerce>2006>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tourism can be classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tangible import</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intangible import</div>", "<div style=\"font-family:Cambria;font-size:17px;\">visible export</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invisible export</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tourism is classified as an 'invisible export'. This is because when foreign tourists visit a country, they bring foreign currency into the country, which is similar to the country exporting goods or services. However, since no physical goods are being exported, it is termed as 'invisible'.</div>", "topic": "AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>2006>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> X represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">action</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transmission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ideation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receiver</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X represent Receiver( a Person who receives the message and gives feedback)</div>", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE"}, {"id": "objective>Commerce>2006>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the communication process, Y represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the encoder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the medium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the initiator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">noise</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The communication process are:   <br/> 1. Source (Sender): The initiator of the communication process. <br/> 2. Stimulus: The trigger that sets the communication process in motion. <br/> 3. Message: The content or information being communicated. <br/> 4. Encoding: The process of putting thoughts, ideas, and information together into a communicable form. <br/> 5. Transmission (Medium): The means or medium through which the message is delivered. <br/> 6. Noise: Any interference that distorts the message. <br/> 7. Receiver: The person who receives the message. <br/> 8. Decoding: The process of translating and interpreting the received message. <br/> 9. Feedback: The response from the receiver to the sender, indicating whether the message was understood. <br/> Given this arrangement,  these components to the diagram: <br/> Source (Sender): This is labeled as \"sender\" in the diagram. <br/> Stimulus: This might not be explicitly shown in the diagram. <br/> Message: Implicit in the process; the content being communicated. <br/> Encoding: Implicit in the sender's role. <br/> Transmission (Medium): This corresponds to Y in the diagram. <br/> Noise: Not explicitly shown but would affect the transmission (Y). <br/> Receiver: This corresponds to X in the diagram. <br/> Decoding: Implicit in the receiver's role. <br/> Feedback: Explicitly shown as \"Feedback\" in the diagram. <br/>  <br/> So, the correct interpretation of Y in the context of the communication process and the provided diagram is that Y represents the medium or means of transmission.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE"}, {"id": "objective>Commerce>2006>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The input, output and central processing units are the basic component of a computer's</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">memory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">printer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hardware</div>", "<div style=\"font-family:Cambria;font-size:17px;\">software</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The computer hardware which is the physical features of a computer Consist mainly of imput devices, output devices and the central Processing Unit (CPU).</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2006>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An employer insures against his employee's dishonesty by taking up</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fidelity guarantee insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accident insurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">group life assurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endowment policy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">fidelity guarantee insurance Covers the loss arising due to dishonesty, disappearance, and disloyalty of the employees or second party.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2006>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Payment made to the insured by the insurer outside its legal obligation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">premium paid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exgratia payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surrender value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sum assured</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Exgratia payment is a payment made to the insured by the insurer is illegal unlike Indemnification which is a legal way of compensation.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2006>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important social reason for developmental tourism in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promotion of culture interaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of job opportunities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improvement of her balance of payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouragement of international relations</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IMPORTANCE OF TOURISM <br/> -     Tourism activity creates demand <br/> -   Tourism requires country's wholesome development. <br/> -  Motivates to reach global standards. <br/> -   Tourism induces more consumption <br/> -   Tourism industry value chain meets and spread demand across industries and boosts more economic activities i.e. economic development. <br/> -    Source of employment generation <br/> -   Cultural growth <br/> -    Introduction of new technology <br/> -   Source of foreign exchange <br/> -  Country's improved brand image.</div>", "topic": "AIDS TO TRADE: TOURISM : AGENCIES THAT PROMOTE TOURISM & CHALLENGES OF TOURISM"}, {"id": "objective>Commerce>2006>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of transportation that convey a limited variety of products through fixed laid route is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">waterways</div>", "<div style=\"font-family:Cambria;font-size:17px;\">road</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pipeline</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pipeline transportation conveys a limited variety of products (usually liquids or gases) through a fixed laid route. It is used for transporting products like crude oil, natural gas, water, etc.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2006>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A computer that can be used in weather forecast is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a hybrid computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an analog computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a mainframe computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a digital computer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weather forecasting requires the solution of complex mathematical equations that involve both continuous and discrete quantities. Therefore, a digital computer is the best choice for weather forecasting.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2006>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The setting of objectives for an organization and determining how to accomplish them is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">social responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organizing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decision-making</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Planning entails setting goals for a business organization with the determination of accomplishing it.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2006>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aspect of marketing that stimulate buying by providing free gift is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">personal selling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sale promotion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sales promotion is a link between personal selling and advertising that stimulate consumer purchase. It includes trade fair, competition, free sample (bearing the firm's logo), premium offer (offer a low value item as a bonus e.g. tooth brush, biro in tooth paste).</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2006>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The limit of functions, activities and personnel that a supervisor can effectively manage in a Business organization is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">span of control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">delegation of authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chain of command</div>", "<div style=\"font-family:Cambria;font-size:17px;\">authority and responsibility</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Span of control involves the functional limits, activities and personnel that a supervisor can effectively manage in a business organization.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2006>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A seller attracts and retains patronage by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enhancing public relations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhancing sales promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rendering pre-sales service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rendering customer service.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Customer services is the support you offer your customers both before and after they buy and use your products or services that helps them have an easy and enjoyable experience with you. It is a also the assistance and advice provided by a company to those people who buy or use its products or services.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2006>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bond which attract only interest but leave the capital unpaid is refered to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a long-term loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a development bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a redeemable bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an irredeemable bond</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An irredeemable bond is a government bond which has no date of maturity and which therefore provides interest but can never be redeemed at full value.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2006>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A public company has 2,000,000 ordinary share of 50k each and offer 50% for subscription at ₦2 per shares were fully subscribed, calculate the issued capital.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦500,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The issued capital of a company is calculated by multiplying the number of shares issued by the price per share.  <br/>  <br/> In this case, the company has 2,000,000 ordinary shares and offers 50% for subscription at ₦2 per share.  <br/>  <br/> Therefore, the issued capital is: <br/> 50% x 2,000,000  <br/> = 1,000,000  <br/>  <br/> = 1,000,000 x ₦2 per share <br/> =  ₦2,000,000. </div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2006>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main requirement for admission to the second tier securities market is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of three year trading record</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disclosure of all trading activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creation of a good atmosphere for growth and development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guaranteeing of dividend to shareholders</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Second Tier Securities Market (SSM) is a market established by the Nigerian Stock Exchange (NSE) to provide an alternative listing platform for smaller companies. The SSM has lower listing requirements than the Main Market of the NSE, making it a more accessible option for smaller companies. <br/>  <br/> One of the main requirements for admission to the SSM is the disclosure of all trading activities. This means that the company must provide the NSE with information about all of its trading activities, including the number of shares traded, the prices at which they were traded, and the identities of the buyers and sellers. <br/>  <br/> The other requirements for admission to the SSM include: <br/> -  The company must be incorporated in Nigeria. <br/> -  The company must have a minimum share capital of ₦10 million. <br/> -  The company must have a minimum of 100 shareholders. <br/> -  The company must have a three-year track record of profitability.</div>", "topic": "STOCK EXCHANGE : SECOND- TIER SECURITIES MARKET"}, {"id": "objective>Commerce>2006>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">use the information below to answer this questions.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The total sum for financial short-term project is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦40,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦200,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦70,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">₦30,000 i.e, this refers to the current liabilities</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2006>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> use the information below to answer this questions.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What is the capital employed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦230,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦340,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦170,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦300,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total capital employed = fixed asset + current assets  <br/> = ₦180,000 + ₦50,000 <br/>  = ₦230,000.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2006>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a developmental bank in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Union Bank Plc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">First Bank Plc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">First City Monument Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Mortgage Bank</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Federal Mortgage Bank. The Federal Mortgage Bank of Nigeria (FMBN) was established in 1956, known then as the Nigerian Building Society (NBS), a joint venture of the Commonwealth Development Corporation and the Federal and Eastern Governments of Nigeria. The banks overall mandate is to promote the delivery of affordable and modern houses to Nigerians.</div>", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK"}, {"id": "objective>Commerce>2006>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trading on stock exchange in anticipation of price change in the market value of Share is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">speculation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forecasting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expectation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">projection</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Speculation involves trading in stock exchange market with the anticipation of price change in the market value of shares.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2006>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A financial institution which uses its capital strength to acquire controlling interest in other firms can be regarded as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">subsidiary company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holding company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cartel</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Holding company refers to a financial organization which uses its capital strength to acquire a controlling interest in other forms.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>2006>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A current account is beneficial to its holder as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheque can be issued to anybody</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customers can not withdraw frequently</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is only the holder that can make withdrawer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it allows customers the use of passbooks</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cheque can be issued to anybody for withdrawal. This serve as a major advantage to a current account holder unlike other types of account holders.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2006>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of raw materials into finish products creates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">form utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">place utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time utility</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of raw materials into finished products creates 'form utility'. Form utility refers to the value added to goods through a manufacturing or assembly process. By changing the form of the product, you make it more useful to the consumer, hence creating form utility.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2006>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factor which critically determines the choice of occupation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">training</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aptitude</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interest is the strongest factor that determines the choice of occupation. When people are interested in something, they are more likely to be motivated to learn about it and to do well in it. They are also more likely to find satisfaction in their work. <br/>  <br/> Skills and training are also important factors, but they are not as critical as interest. Skills can be learned, and training can be provided. However, it is difficult to learn or train someone to be interested in something. <br/>  <br/> Aptitude is another factor that can influence the choice of occupation. Aptitude is a natural ability or talent for something. However, aptitude is not always a guarantee of success. People with high aptitude for a particular occupation may not be interested in it, or they may not have the necessary skills or training. <br/>  <br/> In conclusion, the factor that most critically determines the choice of occupation is interest. However, skills, training, and aptitude can also play a role.</div>", "topic": "OCCUPATION : MEANING & IMPORTANCE"}, {"id": "objective>Commerce>2006>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital to a business is technically</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an expense</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a profit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The monetary value of the excess of business assets over its liabilities i.e.  Capital = Total assets - Total liabilities. Therefore, capital is the net worth of the business.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2006>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I.Wholesaling.  <br/>  II. Fishing  <br/> III. Canning  <br/>  IV. Retailing  <br/>  The sequence in which the occupation activities above are performed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III, II, I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, I, IV and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III, and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III, I and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of the occupation activities is Fishing (II), Canning (III), Wholesaling (I), and Retailing (IV). This is because fishing is the first step where the fish are caught. The fish are then canned to preserve them. After canning, the canned fish are sold in bulk to wholesalers (wholesaling). The wholesalers then sell the canned fish to retailers (retailing), who sell them to the final consumers.</div>", "topic": "OCCUPATION : TYPES OF OCCUPATION"}, {"id": "objective>Commerce>2006>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The development of commerce resulted from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">importation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The development of commerce resulted from specialization. Specialization refers to the concept where individuals, businesses, or countries focus on producing a limited scope of products or services to gain specific advantages over competitors. This leads to trade as entities exchange goods and services they specialize in for others they need, thus leading to the development of commerce.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2006>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between a private limited liability company and a public limited liability company is that the former</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unable to offer share to the public</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is unable to declare and pay dividend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a higher number of shareholder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pay higher salaries to managers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The private limited liability company is restricted from offering its shares to the public for raising capital unlike the public limited liability company which has the liberty of doing so.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2006>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Materials use for further production of goods and services are known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">export goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermediate goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intermediate goods are goods used for further production of other goods and services. They are not final goods and are used in the production process of other goods. Examples include raw materials like steel in car manufacturing.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2006>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A liquidator's fee is to be charged to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">realization account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revaluation account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reconstruction account</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Realization account is an account or statement used in settling or winding up a business or estate to show the results of the disposition of assets and the liquidation of the debts.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2006>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The safety and quality of products are the social responsibility of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Standards Organization of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Manufacturer's Association of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Corporate Affairs of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">business organization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Standards Organization of Nigeria (SON) is responsible for setting and maintaining product quality and safety standards in Nigeria. They ensure that products meet these standards through testing, certification, and inspection processes. While manufacturers also have a role in producing safe and high-quality products, regulatory bodies like SON play a crucial role in overseeing and enforcing these standards to protect consumers and the public.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2006>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A feature common to privatization and commercialization is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit-making</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit sales</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market expansion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price increases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reasons for commercialization and privatization are: <br/> - efficient management <br/> - participation of private individuals <br/> - to generates more revenue <br/> - autonomy of enterprises <br/> - removal of unproductive enterprises</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2006>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A protection right which can be reviewed or renewed after seven years is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">patent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">design</div>", "<div style=\"font-family:Cambria;font-size:17px;\">registration name</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade mark</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A patent is a form of intellectual property that gives its owner the legal right to exclude others from making, using, or selling an invention for a limited period of years.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2006>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The headquarter of Lake Chad Basin commission is in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Niamey</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N'Djamena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abuja</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Lake Chad Basin Commission is an organisation set up to foster co-operation among countries sharing a common border with Lake Chad with respect to the usuage of the lake. The headquarter of LCBC is in Ndjamena, Chad and established by leaders of four countries: Nigeria, Chad, Niger and Cameroun which signed the treaty establishing the commission in 1964.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2006>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the main source of pollution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">domestic waste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organic waste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gas flaring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial waste</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrial waste is the main source of pollution in Nigeria as most areas of urban centres are being occupied by industrial activities.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : POLLUTION"}, {"id": "objective>Commerce>2006>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"Safeguarding the health of the Nation\" is the slogan used by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NDLEA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NHIS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NAFDAC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EPI</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Safeguarding the health of the Nation\" is the slogan used by NAFDAC. NAFDAC stands for National Agency for Food and Drug Administration and Control. It is a Nigerian federal agency under the Federal Ministry of Health that is responsible for regulating and controlling the manufacture, importation, exportation, advertisement, distribution, sale and use of food, drugs, cosmetics, medical devices, chemicals and packaged water.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>2006>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When one person approves an act previously done by another in the former's name without authority, this is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ratification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estoppel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">illegality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">misrepresentation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When one person approves an act previously done by another in the former's name without authority, this is known as ratification. Ratification is a principal's approval of an act of its agent where the agent lacked authority to legally bind the principal. The term applies to private contract law, international treaties, and constitutionals in federations such as the United States and Canada.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>2006>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The members of ECOWAS include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria, Chad, Gabon and Cape Verde</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Burkina Faso, Nigeria, Niger and Mauritania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea, Mali, Cameroon and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Togo, Niger, Nigeria and Ghana</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. The countries listed in option 4 (Togo, Niger, Nigeria, and Ghana) are all members of ECOWAS. Chad and Gabon (option 1) are not members of ECOWAS, they are members of the Economic Community of Central African States (ECCAS). Cameroon (option 3) is also not a member of ECOWAS, it is a member of both ECCAS and the Central African Economic and Monetary Community (CEMAC). Mauritania (option 2) was a member of ECOWAS but withdrew in 2000.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2006>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important advantage of privatization is the enhancement of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liquidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accountability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profitability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficiency</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages for privatisation is efficient management, participation of private individuals, to generate more revenue, emergence of innovation etc.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2006>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A trade association consist of members engaged in the same trade while a chamber of commerce is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">highly regulated by a government agency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not restricted on a particular industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made up of members that are registered</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made up of firm in the banking industry</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Chamber of Commerce is an association or network of business people designed to promote and protect the interest of its members. It can also be defined as a voluntary association of business executives, tradesmen and other entrepreneurs in a city, town or country. It is also known as \"Board of trade\". A chamber of commerce is not restricted on a particular industry; it's open to all different lines of trade.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2006>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hire purchase is beneficial to the seller because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it enhance his living standard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it increases his turn over</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people pay installmentally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the patronage he enjoys</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hire purchase increases the turnover of the seller in the sense that when the buyer in the agreement defaults completely, the seller has the right to make the goods available for sale to other potential buyers unless the last installment has been paid by the initial buyer then this advantage ceases.</div>", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : ADVANTAGES & DISADVANTAGES"}, {"id": "objective>Commerce>2006>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consumerism aims at protecting the consumer from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">harmful products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drug addiction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smoking cigarettes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alcohol consumption</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer protection seeks to protect and inform consumers by requiring such practices as honest packaging and advertising, product guarantees, and improved safety standards.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION"}, {"id": "objective>Commerce>2006>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major types of warehouse are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturer, bonded, departmental and private</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonded, public, coldroom and private</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturer, bonded, public and departmental</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wholesaler, manufacturer, public and bonded</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The four types of warehouses are; wholesaler warehouse, manufacturer's warehouse, public warehouse and bonded warehouse.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>2006>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The customs and excise department is responsible for the collection of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">royalties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tariffs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charges</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The customs and excise department is primarily responsible for the collection of tariffs. Tariffs are taxes or duties to be paid on a particular class of imports or exports. They are used to regulate trade between countries, often to protect domestic industries from foreign competition.</div>", "topic": "TRADE ( 2) : CUSTOMS, EXCISE, PORTS AUTHORITY ETC."}, {"id": "objective>Commerce>2006>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shop which consist of many stores trading under a single roof and which stocks varies of goods each unit having its own head is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">multiple shop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supermarket</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superstore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">departmental store</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Departmental store is a type of outlet which consist of many stores trading under a single roof and which stocks varies of goods with each unit having its own head.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2006>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An objective of the farmers' association is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure that the price of goods are fair and reasonable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">correct the imbalance between consumer and producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve the methods of selling and advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve a stable market outlet for farm inputs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The objectives are to consider,  discuss, provide advice and articulate the farmers needs, desires, aspirations , problems and views on issues such as pricing policy formulation, provision of marketing facilities for both inputs and produce, provision of adequate and affordable transport of farm produce  etc.</div>", "topic": "TRADE ASSOCIATION : OBJECTIVES , MERIT & DEMERIT"}, {"id": "objective>Commerce>2006>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document used in the purchase and sale of goods which contain other terms of trade are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit note and credit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">delivery note and advice note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invoice and order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quotation and invoice</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Order is a statement of acceptance of the price and terms of trade quoted by the supplier. <br/> Invoice is a form in which the seller lists the items sold to a buyer i.e. it shows the list of what the buyer purchased.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2006>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">in international trade, exchanging goods for other goods and services purchase instead of paying in foreign currency is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">counter trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">terms of trade</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Counter trade is a reciprocal form of international trade in which goods and services are exchanged for other goods or services rather than for hard currency. This type of international trade is more common in developing countries with limited foreign exchange or credit facilities.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2006>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of wholesaler in channel of distribution is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">produce goods in large quantities and sell in small quantities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buy goods directly from the manufacturers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buy goods in large quantities and sell in small quantities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell goods directly to the consumers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The role of wholesalers in the channel of production is to buy goods in large quantities from the producers and sell in small quantities to the retailer.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2006>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Foreign trade also involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">providing services for other countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization and the exchange of goods in a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buying and selling within a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the exchange of goods and services between firms</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Foreign trade doesn't only involve exchange of goods among countries but also provision of services for other countries.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}];
